# state/evals.py — consistency evals for judgment agents (#192). Stdlib only.
# Measures run-to-run agreement of step-capability-tagger (per-step computed color) and
# opportunity-scorer (per-dimension / composite / B-B-P) and writes a confidence sidecar
# (evals/<target>.evals.json) + evals/_index.md. Pure metrics; the N runs are generated by
# the evaluating-consistency skill (Claude dispatches the agents — no API/CLI calls here).
from __future__ import annotations

import json
import sys
from itertools import combinations
from pathlib import Path

if __package__ in (None, ""):  # invoked as a script by absolute path
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

import re
from collections import Counter
from statistics import pstdev

from state.capability import compute_color, parse_step_capability
from engine.compute import score_composite

# Thresholds — module constants so they are testable and CLAUDE.md-overridable in spirit.
DIM_SPREAD_UNSTABLE = 2          # a dimension is unstable when max-min >= this
COMPOSITE_SPREAD_UNSTABLE = 0.5  # composite unstable when max-min > this
DEFAULT_N = 5


def _jaccard(a, b):
    a, b = set(a), set(b)
    if not a and not b:
        return 1.0
    return len(a & b) / len(a | b)


def _mean_pairwise_jaccard(sets):
    pairs = list(combinations(sets, 2))
    if not pairs:
        return 1.0
    return round(sum(_jaccard(a, b) for a, b in pairs) / len(pairs), 3)


def tagger_consistency(run_texts):
    """run_texts: PROC markdown per run, each carrying one **Step capability:** table.
    Returns per-step computed-color agreement + unstable flags (unstable = color not unanimous)."""
    runs = [r for r in (parse_step_capability(t) for t in run_texts) if r]
    steps = sorted({s for r in runs for s in r})
    out_steps = []
    for s in steps:
        attr_sets, colors = [], []
        for r in runs:
            if s not in r:
                continue
            attrs = r[s]["attributes"]
            attr_sets.append(attrs)
            try:
                colors.append(compute_color(attrs))
            except ValueError:
                colors.append("INVALID")
        unanimous = len(set(colors)) <= 1
        out_steps.append({
            "step": s,
            "colors": colors,
            "color_unanimous": unanimous,
            "jaccard_mean": _mean_pairwise_jaccard(attr_sets),
            "unstable": not unanimous,
        })
    return {
        "agent": "step-capability-tagger",
        "n_runs": len(runs),
        "insufficient": len(runs) < 2,
        "unstable_step_count": sum(1 for st in out_steps if st["unstable"]),
        "steps": out_steps,
    }


_DIM_RE = re.compile(r"^\|\s*([A-Za-z][^|]*?)\s*\|\s*(\d)\s*/\s*5\s*\|", re.MULTILINE)
_BBP_RE = re.compile(r"\*\*Classification:\*\*\s*([A-Za-z]+)")


def _parse_scorer_run(text):
    dims = {name.strip(): int(v) for name, v in _DIM_RE.findall(text)}
    m = _BBP_RE.search(text)
    return {"dimensions": dims, "bbp": m.group(1) if m else None}


def scorer_consistency(run_texts):
    """run_texts: scorer entry markdown per run (dimensional table + **Classification:**).
    Only runs with all 6 dimensions count. Unstable = composite spread > 0.5, OR any
    dimension spread >= 2, OR B/B/P not unanimous."""
    parsed = [p for p in (_parse_scorer_run(t) for t in run_texts) if len(p["dimensions"]) == 6]
    dim_names = list(parsed[0]["dimensions"]) if parsed else []

    dims_out, any_dim_unstable = {}, False
    for name in dim_names:
        vals = [p["dimensions"][name] for p in parsed]
        spread = max(vals) - min(vals)
        any_dim_unstable = any_dim_unstable or spread >= DIM_SPREAD_UNSTABLE
        dims_out[name] = {
            "values": vals,
            "spread": spread,
            "stdev": round(pstdev(vals), 2) if len(vals) > 1 else 0.0,
        }

    composites = [score_composite([p["dimensions"][d] for d in dim_names]) for p in parsed]
    composites = [c for c in composites if isinstance(c, (int, float))]
    comp_min = round(min(composites), 2) if composites else None
    comp_max = round(max(composites), 2) if composites else None
    comp_spread = round(comp_max - comp_min, 2) if composites else 0.0

    bbps = [p["bbp"] for p in parsed if p["bbp"]]
    modal = Counter(bbps).most_common(1)[0][0] if bbps else None
    modal_agreement = round(bbps.count(modal) / len(bbps), 2) if bbps else 0.0

    unstable = (comp_spread > COMPOSITE_SPREAD_UNSTABLE
                or any_dim_unstable
                or (bool(bbps) and modal_agreement < 1.0))
    return {
        "agent": "opportunity-scorer",
        "n_runs": len(parsed),
        "insufficient": len(parsed) < 2,
        "dimensions": dims_out,
        "composite_spread": comp_spread,
        "composite_min": comp_min,
        "composite_max": comp_max,
        "bbp": {"values": bbps, "modal": modal, "modal_agreement": modal_agreement},
        "unstable": unstable,
    }


def _run_texts(engagement, phase, target):
    d = Path(engagement) / "_staging" / "evals" / phase / target
    return [p.read_text(encoding="utf-8") for p in sorted(d.glob("run-*.md"))]


def write_target(engagement, phase, target):
    """Read the N staged run files for one target, compute consistency, write the sidecar
    evals/<target>.evals.json and rebuild evals/_index.md. Returns the sidecar path."""
    texts = _run_texts(engagement, phase, target)
    if phase == "phase4":
        result = tagger_consistency(texts)
    elif phase == "phase6":
        result = scorer_consistency(texts)
    else:
        raise ValueError(f"unknown eval phase: {phase!r} (expected phase4 or phase6)")
    result["target"] = target
    result["phase"] = phase
    out = Path(engagement) / "evals" / f"{target}.evals.json"
    out.parent.mkdir(parents=True, exist_ok=True)
    out.write_text(json.dumps(result, indent=2), encoding="utf-8")
    build_index(engagement)
    return out


def build_index(engagement):
    ev = Path(engagement) / "evals"
    ev.mkdir(parents=True, exist_ok=True)
    rows = []
    for f in sorted(ev.glob("*.evals.json")):
        d = json.loads(f.read_text(encoding="utf-8"))
        if d.get("insufficient"):
            status = "Insufficient (n<2)"
            u = 0
        elif d.get("agent") == "step-capability-tagger":
            u = d.get("unstable_step_count", 0)
            status = "Stable" if u == 0 else f"{u} step(s) unstable"
        else:
            u = 1 if d.get("unstable") else 0
            status = "Unstable" if d.get("unstable") else "Stable"
        rows.append((d.get("target", f.stem), d.get("agent", ""), d.get("n_runs", 0), u, status))
    lines = ["| Target | Agent | Runs | Unstable | Status |", "|---|---|---|---|---|"]
    lines += [f"| {t} | {a} | {n} | {u} | {s} |" for t, a, n, u, s in rows]
    (ev / "_index.md").write_text("\n".join(lines) + "\n", encoding="utf-8")


if __name__ == "__main__":
    print(write_target(sys.argv[1], sys.argv[2], sys.argv[3]))
